import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import RatingModal from './RatingModal';

const StoreListing = () => {
  const [stores, setStores] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedStore, setSelectedStore] = useState(null);
  const [showRatingModal, setShowRatingModal] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStores();
  }, []);

  const fetchStores = async () => {
    try {
      const response = await api.get('/stores');
      // Fetch user ratings for each store
      const storesWithRatings = await Promise.all(
        response.data.map(async (store) => {
          try {
            const detailsResponse = await api.get(`/stores/${store.id}`);
            return { ...store, user_rating: detailsResponse.data.user_rating || null };
          } catch {
            return { ...store, user_rating: null };
          }
        })
      );
      setStores(storesWithRatings);
    } catch (error) {
      console.error('Failed to fetch stores:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    setSearchTerm(e.target.value);
  };

  const handleRateStore = (store) => {
    setSelectedStore(store);
    setShowRatingModal(true);
  };

  const handleRatingSubmit = async (rating) => {
    try {
      await api.post('/ratings', {
        storeId: selectedStore.id,
        rating: rating
      });
      await fetchStores(); // Refresh the list
      setShowRatingModal(false);
      alert('Rating submitted successfully!');
    } catch (error) {
      console.error('Failed to submit rating:', error);
      alert('Failed to submit rating');
    }
  };

  const filteredStores = stores.filter(store =>
    store.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    store.address.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return <div className="container">Loading stores...</div>;
  }

  return (
    <div className="container">
      <h1 style={{ marginBottom: '20px' }}>Browse Stores</h1>
      
      <div className="filter-section">
        <input
          type="text"
          placeholder="Search by store name or address..."
          value={searchTerm}
          onChange={handleSearch}
          style={{ gridColumn: 'span 2' }}
        />
      </div>
      
      <div className="card" style={{ overflowX: 'auto' }}>
        <table>
          <thead>
            <tr>
              <th>Store Name</th>
              <th>Address</th>
              <th>Overall Rating</th>
              <th>Your Rating</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {filteredStores.map(store => (
              <tr key={store.id}>
                <td>{store.name}</td>
                <td>{store.address}</td>
                <td>{parseFloat(store.overall_rating).toFixed(1)} ★</td>
                <td>{store.user_rating ? `${store.user_rating} ★` : 'Not rated'}</td>
                <td>
                  <button
                    className="btn btn-primary"
                    onClick={() => handleRateStore(store)}
                  >
                    {store.user_rating ? 'Update Rating' : 'Rate Store'}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      
      {showRatingModal && selectedStore && (
        <RatingModal
          store={selectedStore}
          currentRating={selectedStore.user_rating}
          onClose={() => setShowRatingModal(false)}
          onSubmit={handleRatingSubmit}
        />
      )}
    </div>
  );
};

export default StoreListing;
